// ============================================
// NÓ: criarMapaFases (VERSÃO 2.0 - COM METADADOS)
// Preserva ordem, fase_conclusao, fase_testes, fase_reprovacao
// para evitar dependência de nomes hardcoded
// ============================================

const fases = $input.all().map(item => item.json);
console.log(`Total de fases encontradas: ${fases.length}`);

// Cria mapa rico: { id: { nome, ordem, conclusao, testes, reprovacao, arquivamento } }
const mapaFases = {};
fases.forEach(fase => {
  mapaFases[fase.id] = {
    nome: fase.nome,
    ordem: fase.ordem,
    conclusao: fase.fase_conclusao,
    testes: fase.fase_testes,
    reprovacao: fase.fase_reprovacao,
    arquivamento: fase.fase_arquivamento
  };
});

console.log('Mapa de fases criado:', JSON.stringify(mapaFases, null, 2));

// Log de validação: mostra quais fases são de conclusão, testes e reprovação
const fasesConclusao = Object.entries(mapaFases).filter(([_, f]) => f.conclusao).map(([id, f]) => `${f.nome} (id:${id})`);
const fasesTestes = Object.entries(mapaFases).filter(([_, f]) => f.testes).map(([id, f]) => `${f.nome} (id:${id})`);
const fasesReprovacao = Object.entries(mapaFases).filter(([_, f]) => f.reprovacao).map(([id, f]) => `${f.nome} (id:${id})`);

console.log(`Fases de conclusão: ${fasesConclusao.join(', ') || 'nenhuma'}`);
console.log(`Fases de testes: ${fasesTestes.join(', ') || 'nenhuma'}`);
console.log(`Fases de reprovação: ${fasesReprovacao.join(', ') || 'nenhuma'}`);

return [{
  json: {
    fases_map: mapaFases
  }
}];

// Pega resposta da API de cards
const response = $input.first().json;
const cards = response.results || [];

// Pega accessToken do nó fazLogin
const accessToken = $('fazLogin').item.json.accessToken;

// Pega baseUrl do nó configInicial
const baseUrl = $('configInicial').item.json.baseUrl;

// Pega mapa de fases do nó criarMapaFases (v2: objeto rico)
const mapaFases = $('criarMapaFases').item.json.fases_map;

// Pega todo o config pra passar adiante
const config = $('configInicial').item.json;

console.log(`Total de cards encontrados na API: ${cards.length}`);
console.log(`VERSÃO 4.0: Passando TODOS os cards para buscar logs`);
console.log(`Filtro de ${config.PERIODO_ANALISE_DIAS} dias será aplicado APÓS buscar logs`);

// Função para limpar HTML
function limparHTML(html) {
  if (!html) return '';

  let limpo = html;

  // Remove imagens base64
  limpo = limpo.replace(/data:image\/[^;]+;base64,[A-Za-z0-9+/=]+/gi, '[imagem]');

  // Remove tags de imagem
  limpo = limpo.replace(/<img[^>]*>/gi, '[imagem]');

  // Remove anexos
  limpo = limpo.replace(/<span[^>]*attachment-block[^>]*>.*?<\/span>/gi, '[anexo]');

  // Remove tags HTML mas mantém o texto
  limpo = limpo.replace(/<[^>]+>/g, ' ');

  // Remove espaços múltiplos
  limpo = limpo.replace(/\s+/g, ' ').trim();

  return limpo;
}

// Converte tempo "HH:MM:SS" para horas decimais
function parseTempoParaHoras(tempoStr) {
  if (!tempoStr || tempoStr === "00:00:00") return 0;

  const partes = tempoStr.split(':');
  if (partes.length < 2) return 0;

  const horas = parseInt(partes[0]) || 0;
  const minutos = parseInt(partes[1]) || 0;
  const segundos = parseInt(partes[2]) || 0;

  return horas + (minutos / 60) + (segundos / 3600);
}

// Fase fallback caso o ID não exista no mapa
const faseFallback = {
  nome: 'Desconhecida',
  ordem: 999,
  conclusao: false,
  testes: false,
  reprovacao: false,
  arquivamento: false
};

// Processa TODOS os cards (sem filtro)
const cardsLimpos = cards.map(card => {
  const tempoTrabalhadoHoras = parseTempoParaHoras(card.tempo_decorrido);
  const orcadoHoras = parseTempoParaHoras(card.orcado);

  // Resolve fase do mapa rico (v2)
  const faseInfo = mapaFases[card.fase] || faseFallback;

  return {
    // IDs
    id: card.id,
    chamado: card.id,

    // Informações do card
    titulo: card.titulo || `Card #${card.id}`,
    descricao_limpa: limparHTML(card.descricao),

    // Fase (objeto rico do criarMapaFases v2)
    fase_atual: card.fase,
    fase_atual_nome: faseInfo,

    // Responsáveis (agora com id e nome)
    responsaveis: (card.responsaveis || []).map(r => ({ id: r.id, nome: r.nome })),

    // Métricas
    tempo_decorrido: card.tempo_decorrido,
    tempo_trabalhado_horas: tempoTrabalhadoHoras,
    orcado: card.orcado,
    orcado_horas: orcadoHoras,
    // CORREÇÃO: preserva null para distinguir "não estimado" de "estimado como 0"
    pontos_totais: card.pontos_totais !== null && card.pontos_totais !== undefined 
      ? card.pontos_totais 
      : null,
    em_andamento: card.em_andamento,

    // Datas
    data_criacao: card.data_criacao,
    // CORREÇÃO: data_atualizacao removido (não existe na API)
    data_conclusao: card.data_conclusao,
    data_prevista: card.data_prevista,
    // NOVO: campo que existia na API mas era ignorado
    data_desejada: card.data_desejada || null,

    // CORREÇÃO: campo na API é "tag" (array de IDs), não "tags"
    tags: card.tag || [],

    // NOVO: sub_projeto (pode ser útil para agrupamento)
    sub_projeto: card.sub_projeto || null,

    // Projeto
    projeto_info: card.projeto_info,

    // Auth
    _auth: {
      accessToken: accessToken,
      baseUrl: baseUrl
    },

    // Config (passa adiante para os próximos nós)
    _config: config
  };
});

// Log de validação
console.log(`Cards preparados para buscar logs: ${cardsLimpos.length}`);

// Log de exemplo
if (cardsLimpos.length > 0) {
  const exemplo = cardsLimpos.find(c => c.tempo_trabalhado_horas > 0) || cardsLimpos[0];
  console.log(`Exemplo - Card #${exemplo.id}: tempo_decorrido="${exemplo.tempo_decorrido}" → ${exemplo.tempo_trabalhado_horas.toFixed(2)}h`);
  console.log(`  fase: ${exemplo.fase_atual_nome.nome} (conclusao=${exemplo.fase_atual_nome.conclusao})`);
  console.log(`  pontos: ${exemplo.pontos_totais === null ? 'não estimado' : exemplo.pontos_totais}`);
  console.log(`  tags: [${exemplo.tags.join(', ')}]`);
}

// Stats de qualidade dos dados
const stats = {
  com_descricao: cardsLimpos.filter(c => c.descricao_limpa && c.descricao_limpa.length > 0).length,
  com_tempo: cardsLimpos.filter(c => c.tempo_trabalhado_horas > 0).length,
  com_orcado: cardsLimpos.filter(c => c.orcado_horas > 0).length,
  com_pontos: cardsLimpos.filter(c => c.pontos_totais !== null && c.pontos_totais > 0).length,
  sem_pontos: cardsLimpos.filter(c => c.pontos_totais === null).length,
  com_tags: cardsLimpos.filter(c => c.tags.length > 0).length,
  com_conclusao: cardsLimpos.filter(c => c.data_conclusao).length,
  por_fase_conclusao: cardsLimpos.filter(c => c.fase_atual_nome.conclusao === true).length,
  por_fase_testes: cardsLimpos.filter(c => c.fase_atual_nome.testes === true).length,
  por_fase_reprovacao: cardsLimpos.filter(c => c.fase_atual_nome.reprovacao === true).length
};
console.log(`Stats: ${stats.com_descricao} com descrição, ${stats.com_tempo} com tempo, ${stats.com_orcado} com orçado`);
console.log(`Pontos: ${stats.com_pontos} estimados, ${stats.sem_pontos} não estimados`);
console.log(`Tags: ${stats.com_tags} cards com tags`);
console.log(`Fases: ${stats.por_fase_conclusao} concluídos, ${stats.por_fase_testes} em testes, ${stats.por_fase_reprovacao} reprovados`);

return cardsLimpos.map(card => ({ json: card }));

console.log('TODAS AS KEYS DO INPUT:', JSON.stringify(Object.keys($input.first().json)));
console.log('TEM usuarios_map?', !!$input.first().json.usuarios_map);
console.log('TEM horas_por_equipe?', !!$input.first().json.horas_por_equipe);

const input = $input.first().json;
const todosCards = input.data || [];
const fasesMap = input.fases_map || {};

// ============================================
// NOVO v2.0: Ler dados de usuários/times
// ============================================
const usuariosMap = input.usuarios_map || {};
const horasPorEquipe = input.horas_por_equipe || {};
const totalHorasPeriodo = input.total_horas_periodo || 0;
const metaEquipes = input._meta_equipes || {};
const mapaFornecedorUser = input.mapa_fornecedor_user || {};

console.log('=== PREPARANDO DADOS PARA WF2 (v2.1 corrigido) ===');
console.log(`Total de cards: ${todosCards.length}`);
console.log(`Usuários no mapa: ${Object.keys(usuariosMap).length}`);
console.log(`Horas por equipe: ${JSON.stringify(horasPorEquipe)}`);
console.log(`Total horas período: ${totalHorasPeriodo}h`);

// Pega config do primeiro card (todos têm o mesmo)
const config = todosCards.length > 0 && todosCards[0]._config 
  ? todosCards[0]._config 
  : { DIAS_TRAVADO_RESUMO: 30, projeto_id: null, PERIODO_ANALISE_DIAS: 15 };

// ✅ DINÂMICO: Pega info do projeto do primeiro card (todos têm a mesma)
const projetoInfo = todosCards.length > 0 && todosCards[0].projeto_info 
  ? todosCards[0].projeto_info 
  : {
      id: config.projeto_id,
      nome: "Projeto Sem Nome"
    };

console.log(`Projeto: ${projetoInfo.nome} (ID: ${projetoInfo.id})`);

// ============================================
// Helper: extrair nome da fase de forma segura
// ============================================

function getFaseNome(faseAtualNome) {
  if (!faseAtualNome) return 'Sem Fase';
  if (typeof faseAtualNome === 'string') return faseAtualNome;
  if (typeof faseAtualNome === 'object' && faseAtualNome.nome) return faseAtualNome.nome;
  return 'Sem Fase';
}

function getFaseFlag(faseAtualNome, flag) {
  if (!faseAtualNome || typeof faseAtualNome !== 'object') return false;
  return faseAtualNome[flag] === true;
}

// ============================================
// NOVO v2.0: Enriquecer cards com times
// ============================================

console.log('');
console.log('🏷️ Enriquecendo cards com informação de times...');

let cardsComTimeDesconhecido = 0;
let cardsComTime = 0;

const cardsEnriquecidos = todosCards.map(card => {
  // Cruzar responsáveis com o mapa de usuários
  const times = [];
  const equipesSet = new Set();

  if (card.responsaveis && Array.isArray(card.responsaveis)) {
    card.responsaveis.forEach(resp => {
      const userId = String(resp.id);
      const infoUsuario = usuariosMap[userId];

      if (infoUsuario) {
        times.push({
          equipe: infoUsuario.equipe,
          nome: infoUsuario.nome,
          user_id: resp.id,
          nivel: infoUsuario.nivel,
          cargo: infoUsuario.cargo,
          ativo_no_projeto: infoUsuario.ativo_no_projeto,
          horas_periodo: infoUsuario.horas_periodo
        });
        if (infoUsuario.equipe !== 'A definir' && infoUsuario.equipe !== 'Outros') {
          equipesSet.add(infoUsuario.equipe);
        }
      } else {
        // Responsável não encontrado no mapa (provavelmente cliente)
        times.push({
          equipe: 'Externo',
          nome: resp.nome,
          user_id: resp.id,
          nivel: null,
          cargo: null,
          ativo_no_projeto: null,
          horas_periodo: 0
        });
      }
    });
  }

  const equipesEnvolvidas = [...equipesSet].sort();

  if (equipesEnvolvidas.length > 0) {
    cardsComTime++;
  } else {
    cardsComTimeDesconhecido++;
  }

  return {
    ...card,
    times: times,
    equipes_envolvidas: equipesEnvolvidas
  };
});

console.log(`✅ Cards com equipe identificada: ${cardsComTime}`);
console.log(`⚠️ Cards sem equipe identificada: ${cardsComTimeDesconhecido}`);

// ============================================
// Calcula resumo por status
// FIX v2.1: Categorias MUTUAMENTE EXCLUSIVAS
//   Ordem de prioridade (primeiro match ganha):
//   1. concluidos (conclusao=true OU nome inclui "concluído")
//   2. cancelados (nome inclui "cancelado")
//   3. em_andamento (nome inclui "andamento")
//   4. em_testes (testes=true OU nome inclui "teste")
//   5. aguardando_deploy (nome inclui "deploy")
//   6. pendentes (tudo que sobrou que não é "outros")
// ============================================

// FIX v2.1: Classificação mutuamente exclusiva
function classificarStatus(card) {
  const info = card.fase_atual_nome;
  const nome = getFaseNome(info).toLowerCase();

  // 1. Concluídos: flag conclusao=true OU nome "concluído"
  if (getFaseFlag(info, 'conclusao')) return 'concluidos';
  if (nome.includes('concluído') || nome.includes('concluido')) return 'concluidos';

  // 2. Cancelados
  if (nome.includes('cancelado')) return 'cancelados';

  // 3. Em Andamento
  if (nome.includes('andamento')) return 'em_andamento';

  // 4. Em Testes
  if (getFaseFlag(info, 'testes')) return 'em_testes';
  if (nome.includes('teste')) return 'em_testes';

  // 5. Aguardando Deploy
  if (nome.includes('deploy')) return 'aguardando_deploy';

  // 6. Pendentes (backlog, fila, sprint atual, standby, pendente cliente)
  if (nome.includes('sprint') || nome.includes('backlog') || 
      nome.includes('fila') || nome.includes('standby') || 
      nome.includes('pendente')) return 'pendentes';

  // 7. Outros
  return 'outros';
}

const statusCounts = {
  concluidos: 0,
  cancelados: 0,
  em_andamento: 0,
  em_testes: 0,
  aguardando_deploy: 0,
  pendentes: 0,
  outros: 0
};

const cardsPorStatus = {
  concluidos: [],
  cancelados: [],
  em_andamento: [],
  em_testes: [],
  aguardando_deploy: [],
  pendentes: [],
  outros: []
};

cardsEnriquecidos.forEach(card => {
  const status = classificarStatus(card);
  statusCounts[status]++;
  cardsPorStatus[status].push(card);
});

// VALIDAÇÃO: soma deve ser igual ao total
const somaStatus = Object.values(statusCounts).reduce((a, b) => a + b, 0);
if (somaStatus !== cardsEnriquecidos.length) {
  console.log(`🔴 ERRO: por_status soma ${somaStatus} ≠ ${cardsEnriquecidos.length} cards!`);
} else {
  console.log(`✅ por_status soma ${somaStatus} = ${cardsEnriquecidos.length} cards (mutuamente exclusivo)`);
}

// Atalhos para uso posterior
const concluidos = cardsPorStatus.concluidos;
const cancelados = cardsPorStatus.cancelados;
const emAndamento = cardsPorStatus.em_andamento;
const emTestes = cardsPorStatus.em_testes;
const aguardandoDeploy = cardsPorStatus.aguardando_deploy;
const pendentes = cardsPorStatus.pendentes;
const outros = cardsPorStatus.outros;

// Resumo de anomalias
const cardsComAnomalias = cardsEnriquecidos.filter(c => c.total_anomalias > 0);
const cardsComAlertasCriticos = cardsEnriquecidos.filter(c => c.tem_alertas_criticos === true);

const resumo = {
  total_cards: cardsEnriquecidos.length,
  por_status: statusCounts,
  por_fase: {},
  alertas: {
    cards_travados: cardsEnriquecidos.filter(c => 
      c.dias_na_fase_atual && c.dias_na_fase_atual >= config.DIAS_TRAVADO_RESUMO
    ).length,
    cards_travados_ids: cardsEnriquecidos
      .filter(c => c.dias_na_fase_atual && c.dias_na_fase_atual >= config.DIAS_TRAVADO_RESUMO)
      .map(c => c.id),
    cards_com_anomalias: cardsComAnomalias.length,
    cards_com_alertas_criticos: cardsComAlertasCriticos.length,
    cards_com_alertas_criticos_ids: cardsComAlertasCriticos.map(c => c.id)
  },
  // NOVO v2.0: Resumo de horas e times
  horas: {
    total_horas_periodo: totalHorasPeriodo,
    horas_por_equipe: horasPorEquipe,
    equipes_ativas: Object.keys(horasPorEquipe),
    total_pessoas_ativas: metaEquipes.ativos_no_projeto || 0
  }
};

// por_fase agrupa por NOME da fase (string)
cardsEnriquecidos.forEach(card => {
  const faseNome = getFaseNome(card.fase_atual_nome);
  if (!resumo.por_fase[faseNome]) {
    resumo.por_fase[faseNome] = 0;
  }
  resumo.por_fase[faseNome]++;
});

// ============================================
// NOVO v2.0: Resumo de equipes por status
// ============================================

const equipePorStatus = {};
const statusGroups = {
  concluidos,
  em_andamento: emAndamento,
  em_testes: emTestes,
  aguardando_deploy: aguardandoDeploy,
  pendentes
};

for (const [status, cards] of Object.entries(statusGroups)) {
  const equipesNoStatus = new Set();
  cards.forEach(card => {
    (card.equipes_envolvidas || []).forEach(eq => equipesNoStatus.add(eq));
  });
  equipePorStatus[status] = [...equipesNoStatus].sort();
}

resumo.equipes_por_status = equipePorStatus;

// ============================================
// NOVO v2.0: Horas por card concluído (para seção "Entregas")
// ============================================

const entregasComHoras = concluidos.map(card => ({
  id: card.id,
  titulo: card.titulo,
  tempo_trabalhado_horas: card.tempo_trabalhado_horas || 0,
  equipes_envolvidas: card.equipes_envolvidas || [],
  data_conclusao: card.data_conclusao
}));

resumo.entregas_com_horas = entregasComHoras;

const totalHorasEntregas = entregasComHoras.reduce((sum, e) => sum + e.tempo_trabalhado_horas, 0);
resumo.total_horas_entregas = Math.round(totalHorasEntregas * 100) / 100;

// ============================================
// LOGS
// ============================================

console.log('');
console.log('📊 Resumo gerado:');
console.log(`   Total: ${resumo.total_cards}`);
console.log(`   Concluídos: ${resumo.por_status.concluidos}`);
console.log(`   Cancelados: ${resumo.por_status.cancelados}`);
console.log(`   Em Andamento: ${resumo.por_status.em_andamento}`);
console.log(`   Em Testes: ${resumo.por_status.em_testes}`);
console.log(`   Aguardando Deploy: ${resumo.por_status.aguardando_deploy}`);
console.log(`   Pendentes: ${resumo.por_status.pendentes}`);
console.log(`   Outros: ${resumo.por_status.outros}`);
console.log(`   SOMA: ${somaStatus} (deve ser ${resumo.total_cards})`);
console.log(`   Travados: ${resumo.alertas.cards_travados}`);
console.log(`   Com anomalias: ${resumo.alertas.cards_com_anomalias}`);
console.log(`   Com alertas críticos: ${resumo.alertas.cards_com_alertas_criticos}`);
console.log(`   Período de análise: ${config.PERIODO_ANALISE_DIAS} dias`);

console.log('');
console.log('⏱️ Horas no período:');
console.log(`   Total: ${totalHorasPeriodo}h`);
for (const [equipe, horas] of Object.entries(horasPorEquipe)) {
  console.log(`   ${equipe}: ${horas}h`);
}

console.log('');
console.log('📦 Entregas (concluídos):');
console.log(`   Total entregas: ${entregasComHoras.length}`);
console.log(`   Horas nas entregas: ${resumo.total_horas_entregas}h`);
entregasComHoras.forEach(e => {
  console.log(`   - #${e.id}: ${e.titulo} (${e.tempo_trabalhado_horas}h) [${e.equipes_envolvidas.join(', ')}]`);
});

console.log('');
console.log('   Por fase:');
for (const [fase, count] of Object.entries(resumo.por_fase)) {
  console.log(`     ${fase}: ${count}`);
}

// ============================================
// OUTPUT — Formato que o WF2 espera
// FIX v2.1: Removidas chaves top-level redundantes
//   - usuarios → dados já estão em cards[].times[]
//   - horas_por_equipe → já está em resumo.horas.horas_por_equipe
//   - total_horas_periodo → já está em resumo.horas.total_horas_periodo
// ============================================

return [{
  json: {
    projeto_info: projetoInfo,
    cards: cardsEnriquecidos,
    fases: fasesMap,
    resumo: resumo,
    metadados_coleta: {
      periodo_analise_dias: config.PERIODO_ANALISE_DIAS,
      data_coleta: new Date().toISOString(),
      total_cards_coletados: cardsEnriquecidos.length
    },
    _config: config  // Passa config adiante (será removido pelo limparParaIA)
  }
}];

const input = $input.first().json;
const todosCards = input.cards || [];

console.log('=== IDENTIFICANDO SPRINTS v5.0 (SEMANAS ISO) ===');
console.log('Total de cards para analisar: ' + todosCards.length);

// ============================================
// CONFIGURAÇÕES
// ============================================

// Fases de trabalho ativo (fallback para string matching em logs)
const FASES_TRABALHO_NOMES = [
  'sprint atual',
  'em andamento',
  'conclusão da sprint',
  'aguardando deploy',
  'em testes'
];

// Fases a ignorar (fallback para string matching em logs)
const FASES_IGNORAR_NOMES = [
  'backlog',
  'na fila',
  'standby',
  'cancelado',
  'pendente cliente'
];

// ============================================
// HELPER: extrair nome da fase de forma segura
// Suporta objeto rico E string legada
// ============================================

function getFaseNome(faseAtualNome) {
  if (!faseAtualNome) return null;
  if (typeof faseAtualNome === 'string') return faseAtualNome;
  if (typeof faseAtualNome === 'object' && faseAtualNome.nome) return faseAtualNome.nome;
  return null;
}

// ============================================
// FUNÇÕES DE CLASSIFICAÇÃO DE FASE
// ============================================

// Verifica se é fase de trabalho ativo
// Prioriza flags do objeto rico, fallback para string matching
function isFaseTrabalho(faseAtualNome) {
  if (!faseAtualNome) return false;

  // Se é objeto rico, usar flags booleanos
  if (typeof faseAtualNome === 'object') {
    // Fases de conclusão/arquivamento NÃO são trabalho
    if (faseAtualNome.conclusao === true) return false;
    if (faseAtualNome.arquivamento === true) return false;

    // Testes, reprovação = são trabalho ativo
    if (faseAtualNome.testes === true) return true;
    if (faseAtualNome.reprovacao === true) return true;

    // Para fases sem flags específicos, verificar por nome
    const nome = (faseAtualNome.nome || '').toLowerCase();
    if (FASES_IGNORAR_NOMES.some(f => nome.includes(f))) return false;
    if (FASES_TRABALHO_NOMES.some(f => nome.includes(f))) return true;

    // Se tem ordem intermediária (entre backlog e conclusão), provavelmente é trabalho
    // Ordem típica: Backlog(5) → Na Fila(10) → Sprint(20) → Andamento(30) → Deploy(40) → Testes(50) → Conclusão(55) → Concluído(60)
    if (faseAtualNome.ordem && faseAtualNome.ordem >= 20 && faseAtualNome.ordem <= 50) return true;

    return false;
  }

  // Fallback: string matching (compatibilidade legada)
  const fase = faseAtualNome.toLowerCase();
  if (FASES_IGNORAR_NOMES.some(f => fase.includes(f))) return false;
  if (FASES_TRABALHO_NOMES.some(f => fase.includes(f))) return true;
  return false;
}

// Verifica se um NOME de fase (string dos logs) é fase de trabalho
// Logs sempre retornam nomes como strings, nunca objetos
function isFaseTrabalhoNome(nomeFase) {
  if (!nomeFase) return false;
  const fase = nomeFase.toLowerCase();
  if (FASES_IGNORAR_NOMES.some(f => fase.includes(f))) return false;
  if (FASES_TRABALHO_NOMES.some(f => fase.includes(f))) return true;
  return false;
}

