  const data = card._analise.data_entrada_trabalho;
  const anoISO = getAnoISO(data);
  const semanaISO = getNumeroSemanaISO(data);
  const chave = anoISO + '-W' + String(semanaISO).padStart(2, '0');

  if (!sprintsPorSemana[chave]) {
    const segunda = getSegundaDaSemana(data);
    const domingo = getDomingoDaSemana(data);

    sprintsPorSemana[chave] = {
      codigo: chave,
      inicio: segunda,
      fim: domingo,
      cards: []
    };
