// Calcula tempo em cada fase (tempo decorrido, não trabalhado)
function calcularTempoPorFase(logs) {
  const temposPorFase = {};

  for (let i = 0; i < logs.length - 1; i++) {
    const logAtual = logs[i];
    const logProximo = logs[i + 1];

    const inicio = new Date(logAtual.data);
    const fim = new Date(logProximo.data);
    const horas = (fim - inicio) / (1000 * 60 * 60);

    if (!temposPorFase[logAtual.para]) {
      temposPorFase[logAtual.para] = 0;
    }
    temposPorFase[logAtual.para] += horas;
  }

  if (logs.length > 0) {
    const ultimoLog = logs[logs.length - 1];
    const inicio = new Date(ultimoLog.data);
    const agora = new Date();
    const horas = (agora - inicio) / (1000 * 60 * 60);

    const faseAtualDoLog = ultimoLog.para;
    if (!temposPorFase[faseAtualDoLog]) {
      temposPorFase[faseAtualDoLog] = 0;
    }
    temposPorFase[faseAtualDoLog] += horas;
  }

  return temposPorFase;
}

