];
const CARGOS_VAZIOS = ['-', '', 'n/a', 'na', 'não informado', 'nao informado', 'sem cargo', 'null', 'undefined', '.', '...'];
function classificarEquipe(cargoNome) {
  if (!cargoNome || typeof cargoNome !== 'string') return 'A definir';
  const cargoLower = cargoNome.toLowerCase().trim();
  if (CARGOS_VAZIOS.includes(cargoLower)) return 'A definir';
  for (const regra of REGRAS_EQUIPE) {
    for (const palavra of regra.palavras) {
      if (cargoLower.includes(palavra)) {
        return regra.equipe;
      }
    }
  }
  return 'Outros';
}
function extrairNivel(cargoNome) {
  if (!cargoNome || typeof cargoNome !== 'string') return null;
  const cargoLower = cargoNome.toLowerCase();
  if (CARGOS_VAZIOS.includes(cargoLower.trim())) return null;
  if (cargoLower.includes('estagiário') || cargoLower.includes('estagiario') || cargoLower.includes('estágio') || cargoLower.includes('estagio') || cargoLower.includes('intern')) return 'Estagiário';
  if (cargoLower.includes('júnior') || cargoLower.includes('junior') || cargoLower.includes(' jr') || cargoLower.endsWith(' jr')) return 'Júnior';
  if (cargoLower.includes('pleno') || cargoLower.includes('mid') || cargoLower.includes('middle') || cargoLower.includes('nível ii') || cargoLower.includes('nivel ii')) return 'Pleno';
  if (cargoLower.includes('sênior') || cargoLower.includes('senior') || cargoLower.includes(' sr') || cargoLower.endsWith(' sr')) return 'Sênior';
  if (cargoLower.includes('especialista') || cargoLower.includes('staff') || cargoLower.includes('principal')) return 'Especialista';
  if (cargoLower.includes('líder') || cargoLower.includes('lider') || cargoLower.includes('lead') || cargoLower.includes('tech lead')) return 'Líder';
  if (cargoLower.includes('gerente') || cargoLower.includes('gestor') || cargoLower.includes('manager')) return 'Gerente';
  if (cargoLower.includes('diretor') || cargoLower.includes('director') || cargoLower.includes('cto') || cargoLower.includes('ceo')) return 'Diretor';
  return null;
}
