// Equipes classificadas
const equipesReais = Object.entries(stats.por_equipe)
  .filter(([equipe]) => equipe !== 'A definir' && equipe !== 'Outros')
  .sort((a, b) => b[1].length - a[1].length);
if (equipesReais.length > 0) {
  console.log('EQUIPES CLASSIFICADAS:');
  for (const [equipe, membros] of equipesReais) {
    const ativos = membros.filter(m => m.ativoNoProjeto);
    const horasEquipe = horasPorEquipe[equipe] || 0;
    console.log(`   ${equipe}: ${membros.length} pessoa(s), ${ativos.length} ativo(s), ${horasEquipe}h no período`);
    if (ativos.length > 0) {
      ativos.forEach(m => {
        console.log(`     [user:${m.user_id}|forn:${m.fornecedor_id}] ${m.nome} | "${m.cargo}" | ${m.horasPeriodo}h`);
      });
    }
    const inativos = membros.filter(m => !m.ativoNoProjeto);
    if (inativos.length > 0 && inativos.length <= 5) {
      inativos.forEach(m => {
        console.log(`     [user:${m.user_id}|forn:${m.fornecedor_id}] ${m.nome} (sem horas)`);
      });
    } else if (inativos.length > 5) {
      console.log(`     ... e mais ${inativos.length} sem horas no projeto`);
    }
  }
}
// Cargos não classificados
if (stats.cargos_outros.length > 0) {
  console.log('');
  console.log(`CARGOS NÃO CLASSIFICADOS (${stats.cargos_outros.length}):`);
  stats.cargos_outros.forEach(c => {
    console.log(`   - [user:${c.user_id}|forn:${c.fornecedor_id}] ${c.nome}: "${c.cargo}"`);
  });
}
// Sem cargo mas com horas
if (temposDisponiveis) {
  const semCargoMasAtivos = stats.cargos_a_definir.filter(c => {
    const horasInfo = horasPorFornecedorId[String(c.fornecedor_id)];
    return horasInfo && horasInfo.totalHoras > 0;
  });
  if (semCargoMasAtivos.length > 0) {
    console.log('');
    console.log(`ATENÇÃO: ${semCargoMasAtivos.length} fornecedor(es) SEM CARGO mas COM HORAS:`);
    semCargoMasAtivos.forEach(c => {
      console.log(`   - [user:${c.user_id}|forn:${c.fornecedor_id}] ${c.nome}`);
    });
  }
}
// NOVO: Log de horas por equipe
if (Object.keys(horasPorEquipe).length > 0) {
  console.log('');
  console.log('HORAS POR EQUIPE NO PERÍODO:');
  const equipesOrdenadas = Object.entries(horasPorEquipe).sort((a, b) => b[1] - a[1]);
  for (const [equipe, horas] of equipesOrdenadas) {
    const percentual = totalHorasPeriodo > 0 ? Math.round((horas / totalHorasPeriodo) * 100) : 0;
    console.log(`   ${equipe}: ${horas}h (${percentual}%)`);
  }
  console.log(`   TOTAL: ${totalHorasPeriodo}h`);
}
// Resumos
const resumoEquipes = {};
for (const [equipe, membros] of Object.entries(stats.por_equipe)) {
  resumoEquipes[equipe] = membros.length;
}
const resumoAtivos = {};
for (const [equipe, membros] of Object.entries(stats.por_equipe)) {
  const ativos = membros.filter(m => m.ativoNoProjeto).length;
  if (ativos > 0) {
    resumoAtivos[equipe] = ativos;
  }
}
console.log('');
console.log('Resumo TOTAL por equipe:', JSON.stringify(resumoEquipes));
console.log('Resumo ATIVOS no projeto:', JSON.stringify(resumoAtivos));
console.log('Horas por equipe:', JSON.stringify(horasPorEquipe));
