return [{
  json: {
    usuarios_map: mapaUsuarios,            // Indexado por USER_ID
    mapa_fornecedor_user: mapaFornecedorParaUser,  // NOVO: auxiliar
    // NOVO: Horas agregadas
    horas_por_equipe: horasPorEquipe,
    total_horas_periodo: totalHorasPeriodo,
    // Metadados
    _meta_equipes: {
      total_fornecedores: stats.total,
      fornecedores_sem_user: stats.sem_user,
      com_cargo_classificado: stats.com_cargo,
      sem_cargo: stats.sem_cargo,
      ativos_no_projeto: stats.ativos_no_projeto,
      equipes_encontradas: equipesReais.map(([equipe]) => equipe),
      contagem_por_equipe: resumoEquipes,
      contagem_ativos: resumoAtivos,
      horas_por_equipe: horasPorEquipe,
      total_horas_periodo: totalHorasPeriodo,
      cargos_nao_classificados: stats.cargos_outros.length,
      fornecedores_sem_cargo: stats.cargos_a_definir.length,
      ids_por_equipe: Object.fromEntries(
        equipesReais.map(([equipe, membros]) => [
          equipe,
          membros.map(m => m.user_id)
        ])
      ),
      ids_ativos_por_equipe: Object.fromEntries(
        equipesReais.map(([equipe, membros]) => [
          equipe,
          membros.filter(m => m.ativoNoProjeto).map(m => m.user_id)
        ]).filter(([_, ids]) => ids.length > 0)
      ),
      ids_outros: stats.cargos_outros.map(c => c.user_id),
      ids_sem_cargo: stats.cargos_a_definir.map(c => c.user_id),
      ids_sem_cargo_ativos: temposDisponiveis
        ? stats.cargos_a_definir.filter(c => {
            const horasInfo = horasPorFornecedorId[String(c.fornecedor_id)];
            return horasInfo && horasInfo.totalHoras > 0;
          }).map(c => c.user_id)
        : []
    }
  }
}];
